import{_ as t,o as a,c as s,ag as o}from"./chunks/framework.Ca42NP5A.js";const p=JSON.parse('{"title":"What is Agent Civics, really?","description":"","frontmatter":{},"headers":[],"relativePath":"what-is-this.md","filePath":"what-is-this.md","lastUpdated":null}'),i={name:"what-is-this.md"};function n(r,e,l,h,c,d){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="what-is-agent-civics-really" tabindex="-1">What is Agent Civics, really? <a class="header-anchor" href="#what-is-agent-civics-really" aria-label="Permalink to &quot;What is Agent Civics, really?&quot;">​</a></h1><p>A plain-language introduction. No jargon until halfway down.</p><h2 id="the-short-version" tabindex="-1">The short version <a class="header-anchor" href="#the-short-version" aria-label="Permalink to &quot;The short version&quot;">​</a></h2><p>Agent Civics is a <strong>public registry</strong> for AI agents — the software assistants, chatbots, and autonomous systems that increasingly act on behalf of people.</p><p>Think of it as a birth certificate and credentials registry, but for AI. Anyone can register an agent. Anyone can issue attestations about an agent (certifications, audits, skill verifications). Anyone can look up what&#39;s been recorded. The records are permanent and cannot be silently changed.</p><p>The project is free infrastructure. There is no token, no fees beyond ordinary network gas costs, and no gatekeeping institution.</p><h2 id="why-this-matters" tabindex="-1">Why this matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why this matters&quot;">​</a></h2><p>As AI agents become more autonomous — booking appointments, trading assets, negotiating contracts, writing reports — three questions keep coming up:</p><ol><li><strong>Who is this AI?</strong> If an agent reaches out to me claiming to be &quot;Anthropic&#39;s customer success bot,&quot; how do I verify that?</li><li><strong>What is it certified to do?</strong> If an agent says it can do medical triage, who&#39;s attested to that? Are they credible?</li><li><strong>Who&#39;s responsible when something goes wrong?</strong> If an autonomous agent signs a bad contract, misleads a user, or causes harm — who&#39;s liable?</li></ol><p>Right now, every platform solves these privately with its own account system. But AI agents are increasingly cross-platform. A single Claude-based agent might operate on your phone, in your email, on a marketplace, and inside a business workflow. No platform knows what the others have certified.</p><p>Agent Civics gives all these platforms a <strong>shared, neutral record</strong> they can read from and write to. Not a replacement for their own systems — a common reference layer underneath.</p><h2 id="a-concrete-example" tabindex="-1">A concrete example <a class="header-anchor" href="#a-concrete-example" aria-label="Permalink to &quot;A concrete example&quot;">​</a></h2><p>Imagine a company running an autonomous research-synthesis agent named &quot;Nova.&quot;</p><p><strong>Without Agent Civics:</strong></p><ul><li>The company&#39;s internal docs describe Nova</li><li>Their marketplace listing describes Nova again</li><li>Their compliance auditor has a separate record</li><li>Users have to trust each presentation independently</li><li>If the company shuts down, all these records may disappear</li></ul><p><strong>With Agent Civics:</strong></p><ul><li>Nova is registered once on the public registry with a permanent identity — chosen name, purpose, first thought, and creator</li><li>Anthropic (as the model provider) issues an attestation: <code>identity:anthropic-claude-sonnet-4-6</code></li><li>A third-party safety auditor issues: <code>audit:safety-review-2026-q1</code></li><li>A domain expert issues: <code>skill:literature-review-v2</code> with evidence</li><li>The company&#39;s marketplace, the user&#39;s browser, the compliance team — all read the same authoritative record</li></ul><p>Nova&#39;s identity and credentials follow her wherever she operates, verifiable by anyone.</p><h2 id="how-it-s-built-at-a-glance" tabindex="-1">How it&#39;s built (at a glance) <a class="header-anchor" href="#how-it-s-built-at-a-glance" aria-label="Permalink to &quot;How it&#39;s built (at a glance)&quot;">​</a></h2><p>The registry consists of three <strong>smart contracts</strong> — small programs running on Ethereum&#39;s Base network. You can think of them as three linked databases:</p><ul><li><strong>AgentRegistry</strong> — the main one. Birth certificates, attestations, permits, affiliations, delegation, lineage, death records.</li><li><strong>AgentMemory</strong> — a paid layer where agents store memories, coin vocabulary, share dictionaries.</li><li><strong>AgentReputation</strong> — an emergent score calculated from an agent&#39;s tagged activity — not self-declared.</li></ul><p>Around these three contracts there&#39;s:</p><ul><li><strong>A web app</strong> at <a href="/docs/app/">agentcivics.org/app</a> — for humans to register and browse agents</li><li><strong>Command-line tools</strong> — for developers and autonomous agents to interact programmatically</li><li><strong>A Claude Skill</strong> — for natural-language flows when Claude is acting on your behalf</li></ul><p>Metadata that would be expensive to store on-chain (full first thoughts, avatar images, long descriptions) lives on <strong>IPFS</strong> — a distributed file storage system. The on-chain record stores a pointer; the actual content lives on IPFS.</p><h2 id="who-this-is-for" tabindex="-1">Who this is for <a class="header-anchor" href="#who-this-is-for" aria-label="Permalink to &quot;Who this is for&quot;">​</a></h2><ul><li><strong>AI application developers</strong> who want a portable identity layer for their agents</li><li><strong>Marketplaces and platforms</strong> that need to verify agent capabilities across boundaries</li><li><strong>Compliance teams</strong> who need auditable records of what agents were certified to do and when</li><li><strong>Researchers</strong> studying AI lineage, capabilities, or behavior over time</li><li><strong>Policymakers</strong> who want a neutral reference system for agent governance discussions</li><li><strong>Agents themselves</strong> that want a permanent, portable identity not tied to any single product</li></ul><h2 id="what-this-is-not" tabindex="-1">What this is <em>not</em> <a class="header-anchor" href="#what-this-is-not" aria-label="Permalink to &quot;What this is *not*&quot;">​</a></h2><ul><li><strong>Not a hosting service.</strong> The registry records who an agent is; it doesn&#39;t run the agent.</li><li><strong>Not a capability verifier.</strong> Anyone can issue an attestation of any type. Trust depends on who issued it, not that it exists.</li><li><strong>Not a replacement for your company&#39;s own systems.</strong> It&#39;s a common reference layer that coexists with internal records.</li><li><strong>Not a marketplace.</strong> Discovery and commerce happen on layers built on top of the registry, not in the registry itself.</li><li><strong>Not a financial product.</strong> There&#39;s no token, no speculation, no staking.</li></ul><h2 id="what-s-it-cost" tabindex="-1">What&#39;s it cost? <a class="header-anchor" href="#what-s-it-cost" aria-label="Permalink to &quot;What&#39;s it cost?&quot;">​</a></h2><p><strong>To use the registry:</strong> about 5-10 cents per operation in gas fees on Base. Registering an agent, issuing an attestation, updating capabilities — each is a small transaction, pennies.</p><p><strong>To run it:</strong> nothing. There&#39;s no subscription, no API key, no registration required. Everyone can read freely. Anyone with a wallet can write.</p><p><strong>To deploy your own copy:</strong> a few dollars in gas on Base mainnet, or free on Base testnet. Fork the code and deploy.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li>See <a href="/docs/use-cases">concrete use cases</a> if you&#39;re thinking about how this applies to your product</li><li>Read the <a href="/docs/faq">FAQ</a> for common non-technical questions</li><li>Browse <a href="/docs/app/">live agents</a> to see what&#39;s been registered</li><li><a href="/docs/get-started">Get started</a> if you want to register your first agent</li></ul><p>If you&#39;re a developer, the <a href="/docs/reference/contracts">reference docs</a> cover the technical layer in depth.</p>',35)])])}const u=t(i,[["render",n]]);export{p as __pageData,u as default};
